import { useState } from "react";
import axios from "axios";

const API_BASE_URL = "http://localhost:8080/api";

export default function RegisterPage({ setPage, onBack }) {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [pass, setPass] = useState("");
  const [role, setRole] = useState("user");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleRegister = async () => {
    if (!name || !email || !pass) {
      setError("Please fill in all fields");
      return;
    }

    setLoading(true);
    setError("");

    try {
      const response = await axios.post(`${API_BASE_URL}/users/register`, {
        name,
        email,
        password: pass,
        role
      });

      if (response.data.success) {
        setPage("login");
      }
    } catch (err) {
      console.error("Register error:", err);
      setError(err.response?.data?.message || "Registration failed. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-split">
      {/* Visual Side */}
      <div className="auth-visual">
        <img src="https://images.unsplash.com/photo-1556910103-1c02745aae4d?w=800&h=1200&fit=crop" alt="Chef Cooking" />
        <div className="auth-visual-overlay" />
        <div className="auth-visual-text">
          <h2 className="serif">Share your <br /> culinary journey.</h2>
          <p>Whether you're a professional chef or a home cook, we have a place for your recipes.</p>
        </div>
      </div>

      {/* Form Side */}
      <div className="auth-panel" style={{ position: "relative" }}>
        {/* Back Button */}
        <button 
          onClick={onBack} 
          style={{ 
            position: "absolute", 
            top: "40px", 
            left: "40px", 
            background: "none", 
            border: "none", 
            color: "var(--text-muted)", 
            fontSize: "14px", 
            fontWeight: "600",
            display: "flex",
            alignItems: "center",
            gap: "8px"
          }}
        >
          <span>←</span> Back
        </button>

        <h1 className="auth-heading">Create account</h1>
        <p className="auth-subheading">Start sharing your delicious recipes with the world today.</p>

        {error && (
          <div style={{ background: "#fef2f2", color: "#dc2626", padding: "12px 16px", borderRadius: "var(--radius-md)", marginBottom: "24px", fontSize: "14px", border: "1px solid #fee2e2" }}>
            {error}
          </div>
        )}

        <div className="field-wrap">
          <label className="field-label">Full Name</label>
          <div style={{ position: "relative" }}>
            <span className="field-icon">👤</span>
            <input
              className="field-input"
              type="text"
              placeholder="Full Name"
              value={name}
              onChange={e => setName(e.target.value)}
              disabled={loading}
            />
          </div>
        </div>

        <div className="field-wrap">
          <label className="field-label">Email Address</label>
          <div style={{ position: "relative" }}>
            <span className="field-icon">✉</span>
            <input
              className="field-input"
              type="email"
              placeholder="name@company.com"
              value={email}
              onChange={e => setEmail(e.target.value)}
              disabled={loading}
            />
          </div>
        </div>

        <div className="field-wrap">
          <label className="field-label">Password</label>
          <div style={{ position: "relative" }}>
            <span className="field-icon">🔒</span>
            <input
              className="field-input"
              type="password"
              placeholder="••••••••"
              value={pass}
              onChange={e => setPass(e.target.value)}
              disabled={loading}
            />
          </div>
        </div>

        <div style={{ marginBottom: "32px" }}>
          <label className="field-label">I am a...</label>
          <div style={{ display: "flex", gap: "12px" }}>
            {["user", "chef"].map(r => (
              <button
                key={r}
                onClick={() => setRole(r)}
                style={{
                  flex: 1,
                  padding: "12px",
                  borderRadius: "var(--radius-md)",
                  border: "1.5px solid",
                  borderColor: role === r ? "var(--primary)" : "#e2e8f0",
                  background: role === r ? "#fff" : "#f8fafc",
                  color: role === r ? "var(--primary)" : "#64748b",
                  fontWeight: "700",
                  fontSize: "14px",
                  textTransform: "capitalize",
                  cursor: "pointer",
                  transition: "all 0.2s"
                }}
              >
                {r === "user" ? "Home Cook" : "Professional Chef"}
              </button>
            ))}
          </div>
        </div>

        <button
          className="btn-primary"
          onClick={handleRegister}
          disabled={loading}
          style={{ padding: "14px", fontSize: "15px", marginBottom: "24px" }}
        >
          {loading ? "Creating account..." : "Sign Up"}
        </button>

        <div className="auth-footer">
          Already have an account? <button onClick={() => setPage("login")} style={{ fontWeight: "700" }}>Sign In</button>
        </div>
        <div className="auth-links">
          <button>Privacy Policy</button>
          <button>Terms of Service</button>
          <button>Help Center</button>
        </div>
      </div>
    </div>
  );
}
